// ------------------------------------------------------------
//  Greedy Students – enumeration of all convex polygons (C)
// ------------------------------------------------------------
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>

typedef long long ll;

struct Point { ll x, y; } pts[125];

static inline ll cross(const struct Point *a, const struct Point *b, const struct Point *c) {
    // (b-a) x (c-a)
    return (b->x - a->x) * (c->y - a->y) - (b->y - a->y) * (c->x - a->x);
}

// comparator for polar angle around origin point 'base'
static struct Point *basePtr;
int cmp_angle(const void *pa, const void *pb) {
    const struct Point *a = (const struct Point *)pa;
    const struct Point *b = (const struct Point *)pb;
    ll cr = cross(basePtr, a, b);
    if (cr != 0) return (cr > 0) ? -1 : 1; // decreasing angle (counter‑clockwise)
    // tie‑break by distance
    ll da = (a->x - basePtr->x)*(a->x - basePtr->x) + (a->y - basePtr->y)*(a->y - basePtr->y);
    ll db = (b->x - basePtr->x)*(b->x - basePtr->x) + (b->y - basePtr->y)*(b->y - basePtr->y);
    return (da < db) ? -1 : (da > db);
}

int main(){
    int N; long long K;
    if (scanf("%d %lld", &N, &K)!=2) return 0;
    for(int i=0;i<N;i++) scanf("%lld %lld", &pts[i].x, &pts[i].y);

    // store all doubled areas
    ll *areas = (ll*)malloc(sizeof(ll) * 5000000); // enough for N=120 (≈ 2M polygons)
    size_t areaCnt = 0;

    // temporary DP: for each ordered pair (i,j) we keep a dynamic array of accumulated areas
    // we store only the last area (the chain area) because each chain is unique.
    // To keep memory low we use a vector of vectors of ll.
    // For simplicity in C we allocate a 2‑D array of pointers to dynamic arrays.
    typedef struct { ll *vals; int sz; int cap; } Vec;
    Vec dp[125][125];
    for(int i=0;i<N;i++) for(int j=0;j<N;j++) { dp[i][j].vals=NULL; dp[i][j].sz=0; dp[i][j].cap=0; }

    // main enumeration
    for(int b=0;b<N;b++){
        basePtr = &pts[b];
        // collect other points
        struct Point others[124];
        int idxMap[124]; // original indices
        int m=0;
        for(int i=0;i<N;i++) if(i!=b){ others[m]=pts[i]; idxMap[m]=i; m++; }
        qsort(others, m, sizeof(struct Point), cmp_angle);
        // map sorted order back to original indices
        int order[124];
        for(int i=0;i<m;i++){
            // find original index of others[i]
            for(int j=0;j<N;j++) if(j!=b && pts[j].x==others[i].x && pts[j].y==others[i].y){ order[i]=j; break; }
        }
        // DP over increasing angle
        for(int i=0;i<m;i++){
            int vi = order[i];
            // start a chain of length 2 (b -> vi) – nothing stored yet
            for(int j=i+1;j<m;j++){
                int vj = order[j];
                // chain (b,vi,vj) is a triangle, always convex (since angle order is increasing)
                ll area = llabs(cross(&pts[b], &pts[vi], &pts[vj])); // doubled area of triangle
                // store this chain as a candidate for extension
                // push area into dp[vi][vj]
                Vec *vec = &dp[vi][vj];
                if(vec->sz==vec->cap){ vec->cap = vec->cap?vec->cap*2:4; vec->vals = (ll*)realloc(vec->vals, sizeof(ll)*vec->cap); }
                vec->vals[vec->sz++] = area; // chain area so far (b,vi,vj)
                // a triangle is a valid polygon
                areas[areaCnt++] = area;
            }
        }
        // extend chains
        for(int i=0;i<m;i++){
            int vi = order[i];
            for(int j=i+1;j<m;j++){
                int vj = order[j];
                Vec *cur = &dp[vi][vj];
                if(cur->sz==0) continue;
                for(int k=j+1;k<m;k++){
                    int vk = order[k];
                    if(cross(&pts[vi], &pts[vj], &pts[vk]) <= 0) continue; // not a left turn
                    // extend each chain ending with (vi,vj) by vk
                    Vec *dest = &dp[vj][vk];
                    for(int t=0;t<cur->sz;t++){
                        ll newArea = cur->vals[t] + llabs(cross(&pts[b], &pts[vj], &pts[vk]));
                        // store for further extensions
                        if(dest->sz==dest->cap){ dest->cap = dest->cap?dest->cap*2:4; dest->vals = (ll*)realloc(dest->vals, sizeof(ll)*dest->cap); }
                        dest->vals[dest->sz++] = newArea;
                        // closing polygon: add triangle (b, vk, vi) to get full area
                        ll fullArea = newArea + llabs(cross(&pts[b], &pts[vk], &pts[vi]));
                        areas[areaCnt++] = fullArea;
                    }
                }
                // free memory of dp[vi][vj] as it will never be used again for this base
                free(cur->vals); cur->vals=NULL; cur->sz=cur->cap=0;
            }
        }
        // clean remaining dp entries for this base point
        for(int i=0;i<N;i++) for(int j=0;j<N;j++) if(dp[i][j].vals){ free(dp[i][j].vals); dp[i][j].vals=NULL; dp[i][j].sz=dp[i][j].cap=0; }
    }

    // sort areas descending
    qsort(areas, areaCnt, sizeof(ll), (int(*)(const void*,const void*))[](const void *a, const void *b){ ll aa=*(const ll*)a, bb=*(const ll*)b; return (aa>bb)?-1:(aa<bb); });

    // output first K values
    for(long long i=0;i<K;i++){
        if(i) printf(" ");
        if(i < (long long)areaCnt) printf("%lld", areas[i]);
        else printf("-1");
    }
    printf("\n");
    return 0;
}

